from outlines import prompt, register_filter, unregister_filter

register_filter('shout', str.upper)

@prompt
def greet(text):
    '''{{ text | shout }}'''

print(greet('hello'))

unregister_filter('shout')

@prompt
def greet2(text):
    '''{{ text | shout }}'''

try:
    print(greet2('hello'))
except Exception as e:
    print('Expected error:', type(e).__name__, e)
